		path := filepath.ToSlash(string(record[2:]))
		if path != "" {
			paths = append(paths, path)
		}
	}
	return paths, nil
}

func restoreCheckpointSkipWorktreePaths(projectRoot string, paths []string) error {
	for start := 0; start < len(paths); start += 100 {
		end := start + 100
		if end > len(paths) {
